#include <stdio.h>
int main(){
    int T;
    if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        double f;
        scanf("%lf", &f);
        double c = (f - 32.0) * 5.0 / 9.0;
        printf("%.5f\n", c);
    }
    return 0;
}

